var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"니콜 프라이머! 사장님께 정식으로 인사드립니다!","JPN":"ニコル・プライマー！　社長に正式にご挨拶します！","ENG":" Nicole Primer, reporting to you, Boss!","TWN":"我是妮可·布萊伊莫！正式跟老闆打聲招呼！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"특기는 칵테일 만들기. 좋아하는 건 순정만화와 드라마 정주행. 그리고 키와 몸무게는…!","JPN":"特技はカクテル作り。好きなものは少女漫画とドラマの一気見。そして身長と体重は……！","ENG":" I specialize in making cocktails. I love romance comics and binging TV shows. My height and weight are—","TWN":"我的專長是調製雞尾酒，興趣是看少女漫畫和追劇，身高體重是…！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 거기까진 말 안 해도 괜찮나요?","JPN":"はい？　そこまで言わなくてもいいんですか？","ENG":" Sorry? Oh, I don't have to tell you that.","TWN":"嗯？不用講這麼多喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄송해요. 이렇게 대단한 회사의 면접은 처음이라 조금 긴장해서… 으아, 부끄럽네요.","JPN":"すみません、こんな立派な会社の面接は初めてでして……うわあ、恥ずかしいです。","ENG":" I'm sorry. I've never had an interview with such a big company before... Aww, I'm so nervous.","TWN":"抱歉，這是我第一次到大公司面試，有點緊張…真是不好意思！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 그렇죠. 계약서부터 읽어야죠.","JPN":"あ、そうだ。契約書を読まないと。","ENG":" Oh, yes. I should read my contract first.","TWN":"對吼？要先看合約。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…어라? 요구사항은 칵테일 만들기랑… 대화나누기…? 이건 평소에도 늘 하던 일인데요? 이걸로 충분하신 건가요?","JPN":"……あれ？　要求事項はカクテル作りと……会話……？　これは普段の仕事と変わりませんね。本当にこれでいいんですか？","ENG":" ... Err? The job requirements are... making cocktails and communications? These are something I usually do. Is that all you want from me?","TWN":"…嗯？工作內容是調製雞尾酒…跟聊天…？這不就是我平時在做的事嗎？我只需要做這些？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":" …….","TWN":" ……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"알겠습니다. 앞으로도 손님이라고 부르는 쪽이 편하다는 말씀이시죠?","JPN":"わかりました。これからもお客様と呼んでほしいということですね？","ENG":" Got it. And you want me to continue to call you customer, right?","TWN":"好的，以後就稱呼老闆為客人，這樣您會覺得比較自在對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"휴, 솔직히 안심했어요. 사장님이란 표현은 아직 어색해서… 손님이랑 거리가 멀어지진 않을까 살짝 걱정했거든요.","JPN":"ふう、正直安心しました。社長という表現にまだ慣れなくて……お客様と心の距離が遠くなるんじゃないかと、ちょっと心配したんですよ。","ENG":" Whew. Honestly, I'm relieved. I felt awkward calling you Boss, and I was worried it might create a distance between you and me.","TWN":"呼～好險，本來想說叫老闆有點尷尬…感覺好像有點距離感，所以有點小擔心呢～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그럼, 늘 주문하시던 걸로 드려요?","JPN":"では、飲み物はいつものにしますか？","ENG":" So, you want the usual?","TWN":"那酒的部分就照舊囉？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…네에?!","JPN":"……はいっ！？","ENG":" ... Pardon?","TWN":"…什麼？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제가 좋아하는 걸로… 나눠 마시고 싶다니… 그래도 괜찮은 건가요? 어른끼리라곤 하지만 발언이 좀 불건전하지 않나요?!","JPN":"私が好きなものを……シェアしたいなんて……そんなことしていいんですか？　大人同士とはいえ、少し不健全なイメージがありまして。","ENG":" You want to share my favorite cocktail... with me? Really? I mean, we're adults, but... isn't that a bit inappropriate?","TWN":"準備我喜歡喝的嗎？…您想跟我一起…這樣好嗎？雖然大家都是成熟的大人，但這樣會不會有失體統？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 아뇨. 싫다는 뜻은 아니었어요.","JPN":"い、いえ。別に嫌というわけではありません。","ENG":" Oh, no. I didn't mean I don't want to.","TWN":"沒…沒有啦，不是討厭的意思。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"잠시만 기다려주세요! 마가리타 한 잔 준비하겠습니다!","JPN":"少し待ってください。極上のマルガリータ、今すぐご用意します！","ENG":" Just give me a moment. I'll get you a margarita.","TWN":"那您稍等一下，我去弄杯瑪格麗特來！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};